Methods <p>Enums podem conter métodos.</p> <pre><code>const print = @import("std").debug.print;

const Example = enum {
    A,
    B,
    C,

    pub fn isA(self: Example) bool {
        return self == Example.A;
    }
};

pub fn main() !void {
    print("A? {}\n", .{Example.A.isA()});
    print("A? {}\n", .{Example.B.isA()});
}
</code></pre> <pre><code>A? true
A? false
